from flask import Flask, request, jsonify
import jwt
from jwt import PyJWKClient
from functools import wraps
import datetime

app = Flask(__name__)

# Configuration for JWT
JWT_CONFIG = {
    'HS256': {
        'secret': 'your-256-bit-secret',
        'algorithm': 'HS256'
    },
    'RS256': {
        'jwks_url': 'https://your-auth-server/.well-known/jwks.json',
        'algorithm': 'RS256'
    }
}

def get_jwk_client(jwks_url):
    return PyJWKClient(jwks_url)

def verify_jwt(token, algorithm):
    try:
        if algorithm == 'HS256':
            payload = jwt.decode(token, JWT_CONFIG['HS256']['secret'], algorithms=[JWT_CONFIG['HS256']['algorithm']])
        elif algorithm == 'RS256':
            jwk_client = get_jwk_client(JWT_CONFIG['RS256']['jwks_url'])
            signing_key = jwk_client.get_signing_key_from_jwt(token)
            payload = jwt.decode(token, signing_key.key, algorithms=[JWT_CONFIG['RS256']['algorithm']])
        else:
            raise ValueError("Unsupported algorithm")
        
        # Validate claims
        if 'exp' not in payload or datetime.datetime.fromtimestamp(payload['exp']) < datetime.datetime.now():
            raise jwt.ExpiredSignatureError("Token has expired")
        
        return payload
    except (jwt.ExpiredSignatureError, jwt.InvalidTokenError, ValueError) as e:
        return None

def jwt_required(algorithm):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            token = request.headers.get('Authorization', None)
            if token is None:
                return jsonify({'message': 'Token is missing!'}), 401
            
            token = token.replace('Bearer ', '')
            payload = verify_jwt(token, algorithm)
            if payload is None:
                return jsonify({'message': 'Invalid token!'}), 401
            
            return f(payload, *args, **kwargs)
        return decorated_function
    return decorator

@app.route('/internal', methods=['GET'])
@jwt_required('HS256')
def internal_service(payload):
    return jsonify({'message': 'Access granted to internal service', 'user': payload})

@app.route('/public', methods=['GET'])
@jwt_required('RS256')
def public_service(payload):
    return jsonify({'message': 'Access granted to public service', 'user': payload})

if __name__ == '__main__':
    app.run(debug=True)